const body = $input.first().json.body;
const telefone = (body.telefone || body.from || '').toString().replace(/[^0-9]/g, '');
const mensagem = (body.mensagem || body.message || body.text || '').toString().trim().toLowerCase();
const restaurante_id = body.restaurante_id || body.business_id || '';

return {
  telefone,
  mensagem,
  restaurante_id,
  message_type: body.type || 'text',
  raw: body
};

const sessions = $input.first().json;
if (Array.isArray(sessions) && sessions.length > 0) {
  return { session: sessions[0], exists: true };
}
return { session: null, exists: false };

const data = $input.first().json;
const restaurante = Array.isArray(data) ? data[0] : data;
const agora = new Date();
const horaAtual = agora.getHours() * 60 + agora.getMinutes();

function toMinutos(h) {
  if (!h) return null;
  const partes = h.split(':').map(Number);
  return partes[0] * 60 + (partes[1] || 0);
}

const abertura = toMinutos(restaurante.horario_abertura);
const fechamento = toMinutos(restaurante.horario_fechamento);

let aberto = true;
let motivo = '';

if (!restaurante.ativo) {
  aberto = false;
  motivo = 'Estamos fechados no momento! Aguarde nosso retorno. 😊';
} else if (abertura !== null && fechamento !== null) {
  if (horaAtual < abertura || horaAtual > fechamento) {
    aberto = false;
    motivo = `Estamos fechados! Abrimos às ${restaurante.horario_abertura}. 😊`;
  }
}

return {
  restaurante,
  aberto,
  motivo,
  horaAtual,
  abertura,
  fechamento
};

const data = $input.first().json;
// Enviar mensagem de fechado via Z-API
const telefone = data.telefone || data.cliente?.telefone;
const message = data.motivo || 'Estamos fechados! 😊';

// This node signals the webhook response
return {
  to: telefone,
  message,
  action: 'send_message'
};

// Merge session data with input
const input = $input.first().json;
const sessionData = $('🔎 2. Buscar sessão ativa').first().json;
const session = Array.isArray(sessionData) && sessionData.length > 0 ? sessionData[0] : null;

const menuMsg = input.mensagem;
const etapa = session?.etapa_atual || 'inicio';
const carrinho = session?.carrinho || [];

// Comandos globais
if (menuMsg === 'cancelar') {
  return { acao: 'cancelar', etapa, carrinho };
}

switch (etapa) {
  case 'inicio': return { acao: 'boas_vindas', etapa, carrinho };
  case 'menu': return { acao: 'categoria', etapa, carrinho, opcao: menuMsg };
  case 'categoria': return { acao: 'adicionar_item', etapa, carrinho, opcao: menuMsg };
  case 'bump': return { acao: 'resposta_bump', etapa, carrinho, opcao: menuMsg };
  case 'carrinho':
    if (menuMsg === '2') return { acao: 'upsell', etapa, carrinho };
    return { acao: 'adicionar_mais', etapa, carrinho };
  case 'upsell':
    if (menuMsg === '1') return { acao: 'aceitar_upsell', etapa, carrinho };
    return { acao: 'downsell', etapa, carrinho };
  case 'downsell':
    if (menuMsg === '1') return { acao: 'aceitar_downsell', etapa, carrinho };
    return { acao: 'localizacao', etapa, carrinho };
  case 'localizacao': return { acao: 'coletar_pagamento', etapa, carrinho, localizacao: menuMsg };
  case 'pagamento': return { acao: 'confirmar', etapa, carrinho, pagamento: input.pagamento || menuMsg };
  case 'confirmacao':
    if (menuMsg === '1') return { acao: 'handoff', etapa, carrinho };
    if (menuMsg === '2') return { acao: 'editar', etapa, carrinho };
    return { acao: 'cancelar', etapa, carrinho };
  default: return { acao: 'menu', etapa, carrinho };
}

const clienteData = $input.first().json;
const cliente = Array.isArray(clienteData) ? clienteData[0] : clienteData;
const restaurante = $('🏪 3. Buscar restaurante').first().json;
const r = Array.isArray(restaurante) ? restaurante[0] : restaurante;
const nomeRestaurante = r?.nome || 'Restaurante';

let message = '';
let isNovo = false;

if (!cliente || cliente.total_pedidos === 0) {
  isNovo = true;
  message = `Bem-vindo(a) ao ${nomeRestaurante}! 👋\n\nSomos especialistas em deliver! 😊\n\n1️⃣ Ver cardápio\n2️⃣ Repetir último pedido\n3️⃣ Falar com atendente`;
} else {
  message = `Olá ${cliente.nome}! Que bom ter você de volta! 😊\n\n1️⃣ Ver cardápio\n2️⃣ Repetir último pedido\n3️⃣ Falar com atendente`;
}

return { message, isNovo, nome: cliente?.nome || '', total_pedidos: cliente?.total_pedidos || 0 };

const categorias = $input.first().json;
const lista = Array.isArray(categorias) ? categorias : [];

let message = '🍽️ Cardápio:\n\n';
lista.forEach((cat, i) => {
  message += `${i + 1}️⃣ ${cat.categoria}\n`;
});
message += '\n0️⃣ Voltar';

return {
  message,
  categorias: lista,
  categoria_atual: null
};

const itens = $input.first().json;
const lista = Array.isArray(itens) ? itens : [];
const opcao = parseInt($('🔀 4. Roteador principal').first().json.opcao) - 1;
const categorias = $('📋 6. Cardápio dinâmico').first().json;
const cats = Array.isArray(categorias) ? categorias : [];

// Se estamos na etapa categoria, filtra pela categoria escolhida
const etapa = $('🔀 4. Roteador principal').first().json.etapa;

let itensFiltrados;
if (etapa === 'categoria' && cats[opcao]) {
  const catNome = cats[opcao].categoria;
  itensFiltrados = lista.filter(i => i.categoria === catNome);
} else {
  itensFiltrados = lista;
}

let message = 'Itens disponíveis:\n\n';
itensFiltrados.forEach((item, i) => {
  message += `${i + 1}️⃣ ${item.nome} — R$ ${item.preco.toFixed(2)}\n`;
  if (item.descricao) message += `   ${item.descricao}\n`;
});
message += '\n0️⃣ Voltar';

return {
  message,
  itens: itensFiltrados,
  item_escolhido: null
};

const itens = $('🍔 7. Buscar itens do cardápio').first().json;
const lista = Array.isArray(itens) ? itens : [];
const opcao = parseInt($('🔀 4. Roteador principal').first().json.opcao || '0');
const carrinhoAtual = $('🔀 4. Roteador principal').first().json.carrinho || [];

if (opcao <= 0 || opcao > lista.length) {
  return { acao: 'invalido', carrinho: carrinhoAtual };
}

const itemEscolhido = lista[opcao - 1];
const novoCarrinho = [...carrinhoAtual, {
  id: itemEscolhido.id,
  nome: itemEscolhido.nome,
  preco: itemEscolhido.preco,
  categoria: itemEscolhido.categoria
}];

// Verificar se tem bump
if (itemEscolhido.bump_sugerido_id) {
  return {
    acao: 'bump',
    carrinho: novoCarrinho,
    item_adicionado: itemEscolhido,
    bump_id: itemEscolhido.bump_sugerido_id,
    bump_preco: itemEscolhido.bump_preco,
    bump_nome: ''
  };
}

return {
  acao: 'carrinho',
  carrinho: novoCarrinho,
  item_adicionado: itemEscolhido,
  bump_id: null
};

const bumpData = $input.first().json;
const bump = Array.isArray(bumpData) ? bumpData[0] : bumpData;

return {
  message: `✅ Item adicionado!\n\n🔥 Por +R$ ${bump.preco.toFixed(2)} adicione ${bump.nome}!\n\n1️⃣ Sim\n2️⃣ Não obrigado`,
  bump_item: bump
};

const input = $input.first().json;
const carrinhoAtual = $('🔀 4. Roteador principal').first().json.carrinho || [];
const opcao = $('🔀 4. Roteador principal').first().json.opcao || '';

if (opcao === '1') {
  // Aceitou bump
  const bumpItem = $('🔍 Buscar bump sugerido').first().json;
  const bump = Array.isArray(bumpItem) ? bumpItem[0] : bumpItem;
  const novoCarrinho = [...carrinhoAtual, {
    id: bump.id,
    nome: `${bump.nome} (bump)`,
    preco: bump.preco,
    categoria: bump.categoria
  }];

  return {
    acao: 'carrinho',
    carrinho: novoCarrinho,
    message: 'Ótimo! Adicionado! 🎉\n\n1️⃣ Adicionar mais\n2️⃣ Fechar pedido',
    bump_aceito: true
  };
}

return {
  acao: 'carrinho',
  carrinho: carrinhoAtual,
  message: 'Tudo bem! 😊\n\n1️⃣ Adicionar mais\n2️⃣ Fechar pedido',
  bump_aceito: false
};

const carrinho = $('🔀 4. Roteador principal').first().json.carrinho || [];
const sessionData = $('🔎 2. Buscar sessão ativa').first().json;
const session = Array.isArray(sessionData) && sessionData.length > 0 ? sessionData[0] : null;

// Verificar upsell já ofertado
if (session?.upsell_ofertado) {
  return { acao: 'pular_upsell', carrinho, upsell_ofertado: true };
}

const restauranteData = $('🏪 3. Buscar restaurante').first().json;
const restaurante = Array.isArray(restauranteData) ? restauranteData[0] : restauranteData;
const ticketMedio = restaurante?.ticket_medio || 30;

const totalAtual = carrinho.reduce((sum, item) => sum + (item.preco || 0), 0);

if (totalAtual < ticketMedio) {
  // Buscar item de upsell
  return {
    acao: 'oferecer_upsell',
    carrinho,
    totalAtual,
    diferenca: ticketMedio - totalAtual,
    upsell_ofertado: false
  };
}

return { acao: 'pular_upsell', carrinho, upsell_ofertado: false };

const upsellData = $input.first().json;
const upsell = Array.isArray(upsellData) ? upsellData[0] : upsellData;
const diff = $('💸 9. Verificar upsell').first().json.diferenca;

if (!upsell) {
  return { acao: 'pular_upsell', message: '' };
}

return {
  acao: 'mostrar_upsell',
  message: `🍔 Que tal completar seu pedido?\n\nAdicione ${upsell.nome} por apenas R$ ${upsell.preco.toFixed(2)}!\n\n1️⃣ Aceitar\n2️⃣ Não obrigado`,
  upsell_item: upsell
};

const opcao = $('🔀 4. Roteador principal').first().json.opcao || '';
const carrinhoAtual = $('💸 9. Verificar upsell').first().json.carrinho || [];

if (opcao === '1') {
  const upsellItem = $('🔍 Buscar item upsell').first().json;
  const item = Array.isArray(upsellItem) ? upsellItem[0] : upsellItem;
  const novoCarrinho = [...carrinhoAtual, {
    id: item.id,
    nome: `${item.nome} (upsell)`,
    preco: item.preco,
    categoria: item.categoria
  }];

  return {
    acao: 'localizacao',
    carrinho: novoCarrinho,
    message: '',
    upsell_aceito: true
  };
}

return {
  acao: 'downsell',
  carrinho: carrinhoAtual,
  message: '',
  upsell_aceito: false
};

const sessionData = $('🔎 2. Buscar sessão ativa').first().json;
const session = Array.isArray(sessionData) && sessionData.length > 0 ? sessionData[0] : null;
const carrinhoAtual = $('🔀 4. Roteador principal').first().json.carrinho || [];

if (session?.downsell_ofertado) {
  return { acao: 'pular_downsell', carrinho: carrinhoAtual };
}

return {
  acao: 'oferecer_downsell',
  carrinho: carrinhoAtual,
  downsell_ofertado: false
};

const downsellData = $input.first().json;
const downsell = Array.isArray(downsellData) ? downsellData[0] : downsellData;

if (!downsell) {
  return { acao: 'pular_downsell', message: '' };
}

return {
  acao: 'mostrar_downsell',
  message: `😊 Tudo bem! Que tal experimentar ${downsell.nome} por apenas R$ ${downsell.preco.toFixed(2)}?\n\n1️⃣ Sim\n2️⃣ Não, quero finalizar`,
  downsell_item: downsell
};

const opcao = $('🔀 4. Roteador principal').first().json.opcao || '';
const carrinhoAtual = $('💸 10. Verificar downsell').first().json.carrinho || [];

if (opcao === '1') {
  const downsellItem = $('🔍 Buscar item downsell').first().json;
  const item = Array.isArray(downsellItem) ? downsellItem[0] : downsellItem;
  const novoCarrinho = [...carrinhoAtual, {
    id: item.id,
    nome: `${item.nome} (downsell)`,
    preco: item.preco,
    categoria: item.categoria
  }];

  return {
    acao: 'localizacao',
    carrinho: novoCarrinho,
    message: '',
    downsell_aceito: true
  };
}

return {
  acao: 'localizacao',
  carrinho: carrinhoAtual,
  message: '',
  downsell_aceito: false
};

return {
  message: '📍 Seu pedido é para:

1️⃣ Entrega (delivery)
2️⃣ Retirada no balcão

0️⃣ Voltar'
};

const input = $input.first().json;
const opcao = $('🔀 4. Roteador principal').first().json.opcao || '';

let tipo = '';
let message = '';

if (opcao === '1') {
  tipo = 'entrega';
  message = '📍 Manda seu endereço: Rua, número, bairro';
} else if (opcao === '2') {
  tipo = 'retirada';
  message = '🛍️ OK! Retirada no balcão!\n\nQual forma de pagamento?';
}

return { tipo, message, endereco: null };

const pagData = $input.first().json;
const restaurante = Array.isArray(pagData) ? pagData[0] : pagData;
const formas = restaurante?.formas_pagamento || ['Pix', 'Dinheiro', 'Cartão', 'Débito'];

let message = '💳 Formas de pagamento:\n\n';
formas.forEach((f, i) => {
  message += `${i + 1}️⃣ ${f}\n`;
});nmessage += '\n0️⃣ Voltar';

return { message, formas };

const opcaoIndex = parseInt($('🔀 4. Roteador principal').first().json.opcao || '0') - 1;
const formas = $('💬 12b. Montar menu pagamento').first().json.formas || [];
const pagamento = formas[opcaoIndex] || 'Pix';

let message = pagamento === 'Dinheiro' ? '💰 Troco para quanto?' : '';

return { pagamento, precisa_troco: pagamento === 'Dinheiro', message };

const carrinho = $('🔀 4. Roteador principal').first().json.carrinho || [];
const restauranteData = $('🏪 3. Buscar restaurante').first().json;
const restaurante = Array.isArray(restauranteData) ? restauranteData[0] : restauranteData;
const tipo = $('🔧 11b. Processar tipo entrega').first().json.tipo;
const pagamento = $('🔧 12c. Processar pagamento').first().json.pagamento;
const troco = $('🔀 4. Roteador principal').first().json.opcao || null;

const totalItens = carrinho.reduce((sum, item) => sum + (item.preco || 0), 0);
const freteGratis = restaurante?.valor_frete_gratis || 50;
const frete = totalItens >= freteGratis ? 0 : (restaurante?.valor_minimo || 5);
const totalFinal = totalItens + frete;

const endereco = $('🔧 11b. Processar tipo entrega').first().json.endereco || 'A confirmar';

let resumo = `📋 RESUMO DO PEDIDO\n\n`;
carrinho.forEach((item, i) => {
  resumo += `${i + 1}x ${item.nome} — R$ ${item.preco.toFixed(2)}\n`;
});
resumo += `\n💰 Total itens: R$ ${totalItens.toFixed(2)}`;
resumo += `\n🚚 Frete: ${frete === 0 ? 'GRÁTIS 🎉' : 'R$ ' + frete.toFixed(2)}`;
resumo += `\n💵 Total final: R$ ${totalFinal.toFixed(2)}`;
resumo += `\n📍 ${tipo === 'entrega' ? 'Entrega em: ' + endereco : 'Retirada no balcão'}`;
resumo += `\n💳 Pagamento: ${pagamento}`;
if (troco) resumo += `\n💰 Troco para: R$ ${troco}`;
resumo += `\n\n1️⃣ ✅ Confirmar\n2️⃣ ✏️ Editar\n3️⃣ ❌ Cancelar`;

return {
  message: resumo,
  total_itens: totalItens,
  frete,
  total_final: totalFinal,
  tipo,
  endereco,
  pagamento,
  troco
};

const sessionData = $('🔎 2. Buscar sessão ativa').first().json;
const session = Array.isArray(sessionData) && sessionData.length > 0 ? sessionData[0] : null;
const clienteData = $('👤 5. Buscar/cliente').first().json;
const cliente = Array.isArray(clienteData) ? clienteData[0] : clienteData;
const resumo = $('📋 13. Montar resumo + confirmação').first().json;
const bumps = resumo.itens?.filter(i => i.nome?.includes('(bump)')) || [];

const pedido = {
  restaurante_id: $json.restaurante_id,
  cliente_id: cliente?.id || $json.telefone,
  itens: (resumo.itens || []).map(i => ({
    nome: i.nome?.replace(' (bump)', '').replace(' (upsell)', '').replace(' (downsell)', ''),
    preco: i.preco
  })),
  bumps: bumps.map(b => ({ nome: b.nome, preco: b.preco })),
  upsell: $('🔧 9c. Processar resposta upsell').first().json.upsell_aceito || false,
  total: resumo.total_final,
  tipo: resumo.tipo,
  endereco: resumo.endereco,
  pagamento: resumo.pagamento,
  troco: resumo.troco,
  status: 'aguardando_pagamento'
};

return { pedido, message: '' };

const pedidoId = $('💾 14b. Salvar pedido no Supabase').first().json[0]?.id || '';

return {
  to: $json.telefone,
  message: `✅ Pedido #${pedidoId.slice(0, 8)} recebido!\n\nUm atendente vai confirmar seu pagamento agora. Em breve você recebe a confirmação! 😊\n\nAcompanhe pelo WhatsApp. 🚀`
};

const sessionData = $('🔎 2. Buscar sessão ativa').first().json;
const session = Array.isArray(sessionData) && sessionData.length > 0 ? sessionData[0] : null;

if (!session) {
  return { message: 'Não entendi 😅 Digite o número da opção ou 1 para o cardápio.' };
}

return { message: 'Opção inválida! Digite o número da opção 😊' };

// Cancelar fluxo - resetar sessão
return {
  message: '❌ Pedido cancelado. Digite 1 para voltar ao cardápio! 😊'
};

// Handoff manual para atendente
return {
  to: $json.telefone,
  message: '🔁 Transferindo para um atendente...\n\nEm breve alguém vai te atender! 😊'
};

// Z-API send text
const config = $('📩 Webhook Trigger (WhatsApp)').first().json;
const body = $input.first().json;

return {
  url: 'https://api.z-api.io/instances/{{INSTANCE_ID}}/token/{{TOKEN}}/send-text',
  body: {
    phone: body.to || body.telefone,
    message: body.message
  }
};
